    },
    {
      "time": "3:00 PM",
      "activity": "Takes a short break to do light stretching or scroll through design blogs"
    },
    {
      "time": "5:30 PM",
      "activity": "Wraps up work, updates project boards, sends final notes"
    },
    {
      "time": "6:00 PM",
      "activity": "Goes for a walk or meets friends for coffee"
    },
    {
